        case .register:
            return "/auth/register"
        case .refreshToken:
            return "/auth/refresh"
        case .userProfile:
            return "/users/me"
        case .users:
            return "/users"
        case .user(let id):
            return "/users/\(id)"
        case .updateUser(let id):
            return "/users/\(id)"
        }
    }
    
    var method: HTTPMethod {
        switch self {
        case .login, .register, .refreshToken:
            return .post
        case .userProfile, .users, .user:
            return .get
        case .updateUser:
            return .put
        }
    }
