// MARK: - Token Store

protocol TokenStoring {
    var accessToken: String? { get set }
    var refreshToken: String? { get set }
    func clearTokens()
}

class KeychainTokenStore: TokenStoring {
    static let shared = KeychainTokenStore()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    var accessToken: String? {
        get { return readFromKeychain(key: accessTokenKey) }
        set {
            if let value = newValue {
                saveToKeychain(key: accessTokenKey, value: value)
            } else {
                deleteFromKeychain(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { return readFromKeychain(key: refreshTokenKey) }
        set {
            if let value = newValue {
                saveToKeychain(key: refreshTokenKey, value: value)
            } else {
                deleteFromKeychain(key: refreshTokenKey)
            }
        }
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
    
    private func saveToKeychain(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    private func readFromKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    private func deleteFromKeychain(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client

protocol NetworkClientProtocol {
    func request<T: Decodable>(endpoint: APIEndpoint, body: Encodable?, queryItems: [URLQueryItem]?) async throws -> T
}

class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private var tokenStore: TokenStoring
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private var isRefreshingToken = false
    private var refreshContinuations: [CheckedContinuation<Void, Error>] = []
    
    init(
        environment: Environment = .production,
        tokenStore: TokenStoring = KeychainTokenStore.shared,
        sessionConfiguration: URLSessionConfiguration = .default
    ) {
        self.environment = environment
        self.tokenStore = tokenStore
        
        sessionConfiguration.timeoutIntervalForRequest = 30
        sessionConfiguration.timeoutIntervalForResource = 60
        sessionConfiguration.waitsForConnectivity = true
        
        self.session = URLSession(configuration: sessionConfiguration)
        
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
        
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryItems: [URLQueryItem]? = nil
    ) async throws -> T {
        let urlRequest = try buildRequest(endpoint: endpoint, body: body, queryItems: queryItems)
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknown
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                do {
                    let decoded = try decoder.decode(T.self, from: data)
                    return decoded
                } catch {
                    throw NetworkError.decodingError(error)
                }
                
            case 401:
                // Attempt token refresh and retry
                if endpoint.path != APIEndpoint.login.path &&
                   endpoint.path != APIEndpoint.refreshToken.path {
                    try await refreshAccessToken()
                    // Retry the original request with the new token
                    let retryRequest = try buildRequest(endpoint: endpoint, body: body, queryItems: queryItems)
                    let (retryData, retryResponse) = try await session.data(for: retryRequest)
                    
                    guard let retryHTTPResponse = retryResponse as? HTTPURLResponse else {
                        throw NetworkError.unknown
                    }
                    
                    if retryHTTPResponse.statusCode == 401 {
                        tokenStore.clearTokens()
                        throw NetworkError.unauthorized
                    }
                    
                    guard (200...299).contains(retryHTTPResponse.statusCode) else {
                        let errorMessage = parseErrorMessage(from: retryData)
                        throw NetworkError.serverError(statusCode: retryHTTPResponse.statusCode, message: errorMessage)
                    }
                    
                    do {
                        return try decoder.decode(T.self, from: retryData)
                    } catch {
                        throw NetworkError.decodingError(error)
                    }
                } else {
                    throw NetworkError.unauthorized
                }
                
            default:
                let errorMessage = parseErrorMessage(from: data)
                throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage)
            }
        } catch let error as NetworkError {
            throw error
        } catch {
            throw NetworkError.networkFailure(error)
        }
    }
    
    // MARK: - Private Helpers
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryItems: [URLQueryItem]?
    ) throws -> URLRequest {
        let urlString = environment.baseURL + endpoint.path
        
        guard var components = URLComponents(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        if let queryItems = queryItems, !queryItems.isEmpty {
            components.queryItems = queryItems
        }
        
        guard let url = components.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add auth token for non-auth endpoints
        if let token = tokenStore.accessToken,
           endpoint.path != APIEndpoint.login.path,
           endpoint.path != APIEndpoint.register.path,
           endpoint.path != APIEndpoint.refreshToken.path {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        #if DEBUG
        logRequest(request)
        #endif
        
        return request
    }
    
    private func refreshAccessToken() async throws {
        guard let refreshToken = tokenStore.refreshToken else {
            tokenStore.clearTokens()
            throw NetworkError.unauthorized
        }
        
        // Coalesce multiple simultaneous refresh attempts
        if isRefreshingToken {
            return try await withCheckedThrowingContinuation { continuation in
                refreshContinuations.append(continuation)
            }
        }
        
        isRefreshingToken = true
        
        defer {
            isRefreshingToken = false
            refreshContinuations.forEach { $0.resume() }
            refreshContinuations.removeAll()
        }
        
        let refreshRequest = RefreshTokenRequest(refreshToken: refreshToken)
        let refreshEndpoint = APIEndpoint.refreshToken
        let urlRequest = try buildRequest(endpoint: refreshEndpoint, body: refreshRequest, queryItems: nil)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            tokenStore.clearTokens()
            throw NetworkError.unauthorized
        }
        
        let tokenResponse = try decoder.decode(RefreshTokenResponse.self, from: data)
        tokenStore.accessToken = tokenResponse.accessToken
        tokenStore.refreshToken = tokenResponse.refreshToken
    }
    
    private func parseErrorMessage(from data: Data) -> String? {
        return try? decoder.decode(APIErrorResponse.self, from: data).message
    }
    
    private func logRequest(_ request: URLRequest) {
        print("🌐 [\(request.httpMethod ?? "?")] \(request.url?.absoluteString ?? "")")
        if let body = request.httpBody, let bodyString = String(data: body, encoding: .utf8) {
            print("📦 Body: \(bodyString)")
        }
    }
}

// MARK: - Type Erasure for Encodable

private struct AnyEncodable: Encodable {
    private let encodeFunction: (Encoder) throws -> Void
    
    init(_ encodable: Encodable) {
        self.encodeFunction = encodable.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeFunction(encoder)
    }
}

// MARK: - API Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> AuthResponse
    func register(email: String, password: String, name: String) async throws -> AuthResponse
    func logout()
}

protocol UserServiceProtocol {
    func fetchCurrentUser() async throws -> User
    func fetchUsers(page: Int, perPage: Int) async throws -> UsersResponse
    func fetchUser(id: String) async throws -> User
    func updateUser(id: String, name: String?, avatarURL: String?) async throws -> User
}

class AuthService: AuthServiceProtocol {
    
    private let networkClient: NetworkClientProtocol
    private var tokenStore: TokenStoring
    
    init(
        networkClient: NetworkClientProtocol = NetworkClient.shared,
        tokenStore: TokenStoring = KeychainTokenStore.shared
    ) {
        self.networkClient = networkClient
        self.tokenStore = tokenStore
    }
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: AuthResponse = try await networkClient.request(
            endpoint: .login,
            body: body,
            queryItems: nil
        )
        tokenStore.accessToken = response.accessToken
        tokenStore.refreshToken = response.refreshToken
        return response
    }
    
    func register(email: String, password: String, name: String) async throws -> AuthResponse {
        let body = RegisterRequest(email: email, password: password, name: name)
        let response: AuthResponse = try await networkClient.request(
            endpoint: .register,
            body: body,
            queryItems: nil
        )
        tokenStore.accessToken = response.accessToken
        tokenStore.refreshToken = response.refreshToken
        return response
    }
    
    func logout() {
        tokenStore.clearTokens()
    }
}

class UserService: UserServiceProtocol {
    
    private let networkClient: NetworkClientProtocol
    
    init(networkClient: NetworkClientProtocol = NetworkClient.shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser() async throws -> User {
        return try await networkClient.request(
            endpoint: .userProfile,
            body: nil,
            queryItems: nil
        )
    }
    
    func fetchUsers(page: Int = 1, perPage: Int = 20) async throws -> UsersResponse {
        let queryItems = [
            URLQueryItem(name: "page", value: "\(page)"),
            URLQueryItem(name: "per_page", value: "\(perPage)")
        ]
        return try await networkClient.request(
            endpoint: .users,
            body: nil,
            queryItems: queryItems
        )
    }
    
    func fetchUser(id: String) async throws -> User {
        return try await networkClient.request(
            endpoint: .user(id: id),
            body: nil,
            queryItems: nil
        )
    }
    
    func updateUser(id: String, name: String? = nil, avatarURL: String? = nil) async throws -> User {
        let body = UpdateUserRequest(name: name, avatarURL: avatarURL)
        return try await networkClient.request(
            endpoint: .updateUser(id: id),
            body: body,
            queryItems: nil
        )
    }
}

// MARK: - Environment Configuration Helper

struct AppConfiguration {
    static var current: Environment {
        #if DEBUG
        return .development
        #elseif STAGING
        return .staging
        #else
        return .production
        #endif
    }
    
    static func configureNetworkClient() -> NetworkClient {
        return NetworkClient(environment: current)
    }
}

// MARK: - Usage Example (ViewModel)

@MainActor
class UserViewModel: ObservableObject {
    
    @Published var currentUser: User?
    @Published var users: [User] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var isAuthenticated = false
    
    private let authService: AuthServiceProtocol
    private let userService: UserServiceProtocol
    
    init(
        authService: AuthServiceProtocol = AuthService(),
        userService: UserServiceProtocol = UserService()
    ) {
        self.authService = authService
        self.userService = userService
        self.isAuthenticated = KeychainTokenStore.shared.accessToken != nil
    }
    
    func login(email: String, password: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.login(email: email, password: password)
            currentUser = response.user
            isAuthenticated = true
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func register(email: String, password: String, name: String) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await authService.register(email: email, password: password, name: name)
            currentUser = response.user
            isAuthenticated = true
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func fetchProfile() async {
        isLoading = true
        errorMessage = nil
        
        do {
            currentUser = try await userService.fetchCurrentUser()
        } catch let error as NetworkError where error.localizedDescription == NetworkError.unauthorized.localizedDescription {
            isAuthenticated = false
            errorMessage = error.errorDescription
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func fetchUsers(page: Int = 1) async {
        isLoading = true
        errorMessage = nil
        
        do {
            let response = try await userService.fetchUsers(page: page, perPage: 20)
            if page == 1 {
                users = response.users
            } else {
                users.append(contentsOf: response.users)
            }
        } catch {
            errorMessage = (error as? NetworkError)?.errorDescription ?? error.localizedDescription
        }
        
        isLoading = false
    }
    
    func logout() {
        authService.logout()
        currentUser = nil
        users = []
        isAuthenticated = false
    }
}